fun solve(nums: Array<Long>, k: Long): Long {
    val n = nums.size
    nums.sort()
    var maxLen = 1L
    for (i in 0 until n) {
        val target = nums[i] * k
        var low = i
        var high = n - 1
        var res = i - 1
        while (low <= high) {
            val mid = (low + high) / 2
            if (nums[mid] <= target) {
                res = mid
                low = mid + 1
            } else {
                high = mid - 1
            }
        }
        val currentLen = res - i + 1
        if (currentLen > maxLen) {
            maxLen = currentLen.toLong()
        }
    }
    return n.toLong() - maxLen
}
